import csv
import io
import boto3
from botocore import UNSIGNED
from botocore.client import Config

source = 'datagov/vaccine-hesitancy-for-covid-19-county-and-local-estimates/files/rows.txt'
bucket = 'lakeqa-yc4103-datalake'
node_1_answer = ['CO', 'KS', 'TX']
state_names = {'COLORADO': 'CO', 'KANSAS': 'KS', 'TEXAS': 'TX'}
sums = {state: 0.0 for state in node_1_answer}
counts = {state: 0 for state in node_1_answer}
obj = boto3.client('s3', region_name='us-east-1', config=Config(signature_version=UNSIGNED)).get_object(Bucket=bucket, Key=source)
reader = csv.DictReader(io.TextIOWrapper(obj['Body'], encoding='utf-8'))
for row in reader:
    state = state_names.get(row['State'])
    if state in sums:
        sums[state] += float(row['Estimated hesitant or unsure'])
        counts[state] += 1
averages = {state: round(sums[state] / counts[state], 4) for state in node_1_answer}
answer = dict(sorted(averages.items(), key=lambda item: (-item[1], item[0])))
